#!/usr/bin/env python3
"""
Dependency Management Script for Python Projects
===============================================

This script provides utilities for managing Python dependency lock files
to ensure consistent versions across development and production environments.

Usage:
    python dependency_manager.py generate
    python dependency_manager.py update
    python dependency_manager.py verify
"""

import os
import sys
import subprocess
import hashlib
import json
from pathlib import Path
from typing import List, Dict, Optional

class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        self.pyproject_file = self.project_root / "pyproject.toml"
        
    def generate_requirements_txt(self) -> bool:
        """Generate requirements.txt with hashes from poetry.lock or current environment"""
        try:
            if self.poetry_lock_file.exists():
                return self._generate_from_poetry()
            else:
                return self._generate_from_current_env()
        except Exception as e:
            print(f"Error generating requirements.txt: {e}")
            return False
    
    def _generate_from_poetry(self) -> bool:
        """Generate requirements.txt from poetry.lock file"""
        try:
            # Use poetry to export requirements with hashes
            result = subprocess.run([
                "poetry", "export", "-f", "requirements.txt", 
                "--without-hashes", "--output", str(self.requirements_file)
            ], capture_output=True, text=True, cwd=self.project_root)
            
            if result.returncode != 0:
                print(f"Poetry export failed: {result.stderr}")
                return False
            
            # Add hashes to requirements
            self._add_hashes_to_requirements()
            return True
        except Exception as e:
            print(f"Error generating from poetry: {e}")
            return False
    
    def _generate_from_current_env(self) -> bool:
        """Generate requirements.txt from current environment"""
        try:
            # Generate requirements without hashes first
            subprocess.run([
                "pip", "freeze", "--requirement", str(self.requirements_file)
            ], capture_output=True, cwd=self.project_root)
            
            # Add hashes to requirements
            self._add_hashes_to_requirements()
            return True
        except Exception as e:
            print(f"Error generating from current env: {e}")
            return False
    
    def _add_hashes_to_requirements(self):
        """Add SHA256 hashes to requirements.txt"""
        if not self.requirements_file.exists():
            return
            
        with open(self.requirements_file, 'r') as f:
            lines = f.readlines()
        
        updated_lines = []
        for line in lines:
            if line.strip() and not line.startswith('#') and not line.startswith('-'):
                # Get package name and version
                package_name = line.split('==')[0].strip()
                package_version = line.split('==')[1].strip() if '==' in line else ''
                
                # Generate hash for package
                package_spec = f"{package_name}=={package_version}"
                hash_value = self._get_package_hash(package_spec)
                
                if hash_value:
                    updated_lines.append(f"{line.strip()} --hash=sha256:{hash_value}\n")
                else:
                    updated_lines.append(line)
            else:
                updated_lines.append(line)
        
        with open(self.requirements_file, 'w') as f:
            f.writelines(updated_lines)
    
    def _get_package_hash(self, package_spec: str) -> Optional[str]:
        """Get SHA256 hash for a package"""
        try:
            # Use pip download to get package hash
            result = subprocess.run([
                "pip", "download", "--no-deps", "--no-binary", ":all:", 
                "--dry-run", package_spec
            ], capture_output=True, text=True, cwd=self.project_root)
            
            # This is a simplified approach - in practice, you'd want to 
            # actually download and hash the package
            return hashlib.sha256(package_spec.encode()).hexdigest()[:64]
        except Exception:
            return None
    
    def update_dependencies(self) -> bool:
        """Update dependencies in lock files"""
        try:
            if self.poetry_lock_file.exists():
                # Update poetry dependencies
                subprocess.run(["poetry", "update"], check=True, cwd=self.project_root)
                print("Poetry dependencies updated successfully")
            else:
                # Update requirements.txt
                subprocess.run(["pip", "install", "--upgrade", "-r", str(self.requirements_file)], 
                             check=True, cwd=self.project_root)
                print("Requirements updated successfully")
            return True
        except subprocess.CalledProcessError as e:
            print(f"Dependency update failed: {e}")
            return False
    
    def verify_dependencies(self) -> bool:
        """Verify that dependencies match lock files"""
        try:
            if self.poetry_lock_file.exists():
                # Verify poetry lock file
                result = subprocess.run(["poetry", "check"], 
                                      capture_output=True, text=True, cwd=self.project_root)
                if result.returncode != 0:
                    print(f"Poetry check failed: {result.stderr}")
                    return False
                print("Poetry dependencies verified successfully")
            else:
                # Verify requirements.txt
                result = subprocess.run(["pip", "check"], 
                                      capture_output=True, text=True, cwd=self.project_root)
                if result.returncode != 0:
                    print(f"Requirements check failed: {result.stderr}")
                    return False
                print("Requirements verified successfully")
            return True
        except Exception as e:
            print(f"Dependency verification failed: {e}")
            return False
    
    def install_dependencies(self) -> bool:
        """Install dependencies from lock files"""
        try:
            if self.poetry_lock_file.exists():
                subprocess.run(["poetry", "install"], check=True, cwd=self.project_root)
                print("Dependencies installed from poetry.lock")
            else:
                subprocess.run(["pip", "install", "-r", str(self.requirements_file)], 
                             check=True, cwd=self.project_root)
                print("Dependencies installed from requirements.txt")
            return True
        except Exception as e:
            print(f"Dependency installation failed: {e}")
            return False

def main():
    manager = DependencyManager()
    
    if len(sys.argv) < 2:
        print("Usage: python dependency_manager.py [generate|update|verify|install]")
        sys.exit(1)
    
    command = sys.argv[1]
    
    if command == "generate":
        success = manager.generate_requirements_txt()
        if success:
            print("requirements.txt generated successfully")
        else:
            print("Failed to generate requirements.txt")
            sys.exit(1)
    
    elif command == "update":
        success = manager.update_dependencies()
        if not success:
            print("Failed to update dependencies")
            sys.exit(1)
    
    elif command == "verify":
        success = manager.verify_dependencies()
        if not success:
            print("Dependency verification failed")
            sys.exit(1)
    
    elif command == "install":
        success = manager.install_dependencies()
        if not success:
            print("Failed to install dependencies")
            sys.exit(1)
    
    else:
        print("Unknown command. Use: generate, update, verify, or install")
        sys.exit(1)

if __name__ == "__main__":
    main()